// Aquí procesamos el webhook de Evolution API
// Evolution API puede enviar en $json directamente o en $json.body
const raw = $input.first().json;
const body = raw.body || raw;

if (!body || body.event !== 'messages.upsert') {
  return [{ json: { procesar: false, accion: null, reason: 'No es messages.upsert: ' + (body && body.event) } }];
}

const data = body.data;
if (!data || !data.message) {
  return [{ json: { procesar: false, accion: null, reason: 'Sin data.message' } }];
}

const message = data.message;

const GROUP_JID = '120363405067640480@g.us';

if (data.key.remoteJid !== GROUP_JID) {
  return [{ json: { procesar: false, accion: null, reason: 'Mensaje fuera del grupo: ' + data.key.remoteJid } }];
}

if (data.key.fromMe) {
  return [{ json: { procesar: false, accion: null, reason: 'Mensaje de mi mismo' } }];
}

const senderJid = data.key.participant || data.key.remoteJid;
const senderName = data.pushName || senderJid.split('@')[0];

// ── Detectar comandos de texto ───────────────────────────────────
const textMsg = message.conversation || (message.extendedTextMessage && message.extendedTextMessage.text) || '';
const texto = textMsg.trim().toLowerCase();

if (texto.length > 0) {
  // Tabla de posiciones
  if (/tabla|posiciones|ranking|top|clasificaci/.test(texto)) {
    return [{ json: { procesar: true, accion: 'tabla', senderId: senderJid, senderName: senderName, groupJid: GROUP_JID } }];
  }
  // Mis puntos
  if (/mis punt|cuantos punt|mi puntaje|mis pt|puntos tengo/.test(texto)) {
    return [{ json: { procesar: true, accion: 'mis_puntos', senderId: senderJid, senderName: senderName, groupJid: GROUP_JID } }];
  }
  // Mi posición
  if (/mi posici|mi lugar|que puesto|mi ranking/.test(texto)) {
    return [{ json: { procesar: true, accion: 'mi_posicion', senderId: senderJid, senderName: senderName, groupJid: GROUP_JID } }];
  }
  // Ayuda
  if (/ayuda|help|comandos|que haces|instrucciones|hola bot/.test(texto)) {
    return [{ json: { procesar: true, accion: 'ayuda', senderId: senderJid, senderName: senderName, groupJid: GROUP_JID } }];
  }
  // No reconocido → ignorar
  return [{ json: { procesar: false, accion: null, reason: 'Texto no reconocido: ' + texto } }];
}

// ── Detectar imagen con puntos ───────────────────────────────────
if (!message.imageMessage) {
  return [{ json: { procesar: false, accion: null, reason: 'No es texto ni imagen' } }];
}

const caption = (message.imageMessage.caption || '').trim();
const match = caption.match(/(?:puntos?|#puntos?)\s*(\d+(?:[.,]\d+)?)/i);

if (!match) {
  return [{ json: { procesar: false, accion: null, reason: 'Imagen sin #puntos en el caption' } }];
}

const puntos = parseFloat(match[1].replace(',', '.'));

return [{ json: { 
  procesar: true,
  accion: 'registrar',
  puntos: puntos,
  senderId: senderJid,
  senderName: senderName,
  timestamp: new Date().toISOString(),
  messageId: data.key.id,
  groupJid: GROUP_JID
} }];

// ── RESPONDER: MIS PUNTOS + MI POSICIÓN ──
const EVOLUTION_URL      = 'https://evolution.sekaitech.com.pe';
const EVOLUTION_API_KEY  = '36336609909C-4FFE-AB5D-2F619AE65495';
const EVOLUTION_INSTANCE = 'sekaitech';

const inp = $input.first().json;
return [{ json: {
  _accion: inp.accion,
  senderId: inp.senderId,
  senderName: inp.senderName,
  groupJid: inp.groupJid,
