// ── CALCULAR Y RESPONDER CONSULTA DEL USUARIO ──
const EVOLUTION_URL      = 'https://evolution.sekaitech.com.pe';
const EVOLUTION_API_KEY  = '36336609909C-4FFE-AB5D-2F619AE65495';
const EVOLUTION_INSTANCE = 'sekaitech';

// Contexto del usuario viene del nodo Router (rama FALSE)
const ctx = $('Router de Acciones').first().json;
const accion   = ctx.accion;
const mySender = ctx.senderId;
const myName   = ctx.senderName;
const groupJid = ctx.groupJid;

// Todos los registros del historial (items de Google Sheets)
const rows = $input.all().map(e => e.json);

// Calcular ranking acumulado
const puntajes = {};
rows.forEach(row => {
  const userId = row['Usuario ID'];
  if (!userId) return;
  const puntos = parseFloat((row['Puntos'] || '0').toString().replace(/[^0-9.]/g, '')) || 0;
  if (!puntajes[userId]) puntajes[userId] = { nombre: row['Nombre'] || 'Anónimo', puntos: 0 };
  puntajes[userId].puntos += puntos;
});

const ranking = Object.entries(puntajes)
  .map(([id, v]) => ({ id, nombre: v.nombre, puntos: v.puntos }))
  .sort((a, b) => b.puntos - a.puntos);

let respuesta = '';

if (accion === 'tabla') {
  const medallas = ['🥇','🥈','🥉','4️⃣','5️⃣'];
  const top5 = ranking.slice(0, 5);
  if (top5.length === 0) {
    respuesta = '📋 *TABLA DE POSICIONES — Sorteo Fin de Año*\n\nAún no hay puntos registrados. ¡Sube tu primera boleta!';
  } else {
    respuesta = '🏆 *TABLA DE POSICIONES — Sorteo Fin de Año*\n' + '─'.repeat(30) + '\n';
    top5.forEach((u, i) => {
      const marca = u.id === mySender ? ' 👈 *tú*' : '';
      respuesta += medallas[i] + ' *' + u.nombre + '* — ' + u.puntos.toFixed(2) + ' pts' + marca + '\n';
    });
    if (ranking.length > 5) respuesta += '\n_...y ' + (ranking.length - 5) + ' participante(s) más_';
    respuesta += '\n\n💡 Sube más boletas con _#puntos [cantidad]_ para subir.';
  }
} else if (accion === 'mis_puntos') {
  const me = puntajes[mySender];
  if (!me) {
    respuesta = '👤 *' + myName + '*, todavía no tienes puntos registrados.\n\n📸 Envía una imagen de tu boleta con el texto _#puntos [cantidad]_ para empezar.';
  } else {
    respuesta = '✨ *Tus puntos, ' + myName + '*\n' + '─'.repeat(25) + '\n💰 Total acumulado: *' + me.puntos.toFixed(2) + ' puntos*\n\n¡Sigue subiendo boletas para escalar posiciones! 🚀';
  }
} else if (accion === 'mi_posicion') {
  const pos = ranking.findIndex(u => u.id === mySender);
  if (pos === -1) {
    respuesta = '👤 *' + myName + '*, aún no tienes puntos. ¡Comienza subiendo tu primera boleta con _#puntos [cantidad]_!';
  } else {
    const emojis = ['🥇','🥈','🥉'];
    const medalla = emojis[pos] !== undefined ? emojis[pos] : '#' + (pos + 1);
    const me = ranking[pos];
    respuesta = '📍 *Tu posición actual, ' + myName + '*\n' + '─'.repeat(25) + '\n' + medalla + ' Posición: *' + (pos + 1) + '° de ' + ranking.length + '*\n💰 Puntos: *' + me.puntos.toFixed(2) + '*';
    if (pos > 0) {
      const diff = ranking[pos - 1].puntos - me.puntos;
      respuesta += '\n\n⬆️ Te faltan *' + diff.toFixed(2) + ' pts* para superar al ' + pos + '°';
    } else {
      respuesta += '\n\n👑 ¡Estás en primer lugar! Mantén el liderazgo.';
    }
  }
} else {
  respuesta = '❓ No entendí el comando. Escribe *ayuda* para ver qué puedo hacer.';
}

return [{ json: {
  url: EVOLUTION_URL + '/message/sendText/' + EVOLUTION_INSTANCE,
  headers: { 'apikey': EVOLUTION_API_KEY, 'Content-Type': 'application/json' },
  body: { number: groupJid, text: respuesta }
} }];

